// Process crypto data for AI analysis
const items = $input.all();
const symbolNode = $('Extract Symbol').first();

let cryptoData = {
  symbol: symbolNode?.json?.symbolCode || 'BTC',
  fullName: symbolNode?.json?.symbol || 'bitcoin',
  timestamp: new Date().toISOString(),
  price: {},
  market: {},
  news: [],
  social: {},
  technical: {}
};

try {
  // Process each item from the 4 HTTP requests
  for (const item of items) {
    const data = item.json;

    // CoinGecko Price Data (from market_chart endpoint)
    if (data.prices && Array.isArray(data.prices)) {
      const prices = data.prices.map(p => p[1]);
      const last24 = prices.slice(-24);

      cryptoData.price = {
        current: prices[prices.length - 1].toFixed(2),
        change_24h: prices.length >= 24 ? ((prices[prices.length - 1] - prices[prices.length - 24]) / prices[prices.length - 24] * 100).toFixed(2) : '0',
        high_24h: Math.max(...last24).toFixed(2),
        low_24h: Math.min(...last24).toFixed(2),
        history: prices.slice(-24)
      };
    }

    // CoinGecko Market Data (from coins endpoint)
    if (data.market_data) {
      cryptoData.market = {
        market_cap: (data.market_data.market_cap?.usd || 0).toLocaleString('en-US'),
        volume_24h: (data.market_data.total_volume?.usd || 0).toLocaleString('en-US'),
        ath: (data.market_data.ath?.usd || 0).toFixed(2),
        ath_change: (data.market_data.ath_change_percentage?.usd || 0).toFixed(2),
        rank: data.market_data.market_cap_rank || 0
      };
    }

    // CryptoPanic News - Check multiple possible response structures
    if (data.results && Array.isArray(data.results) && data.results.length > 0) {
      cryptoData.news = data.results.slice(0, 10).map(article => ({
        title: article.title,
        published: article.published_at,
        votes: article.votes || {},
        sentiment: (article.votes?.positive || 0) > (article.votes?.negative || 0) ? 'bullish' : 
                  (article.votes?.negative || 0) > (article.votes?.positive || 0) ? 'bearish' : 'neutral',
        source: article.source?.title || 'Unknown'
      }));
    }
    // Fallback: Use NewsAPI articles as crypto news if CryptoPanic fails
    else if (data.articles && Array.isArray(data.articles) && cryptoData.news.length === 0) {
      const cryptoArticles = data.articles.filter(a => {
        const text = ((a.title || '') + ' ' + (a.description || '')).toLowerCase();
        return text.includes('bitcoin') || text.includes('btc') || text.includes('ethereum') || text.includes('eth') || text.includes('crypto');
      }).slice(0, 10);

      if (cryptoArticles.length > 0) {
        const bullishWords = ['surge', 'rally', 'bullish', 'gain', 'rise', 'up', 'high', 'boost', 'positive', 'soar'];
        const bearishWords = ['crash', 'fall', 'bearish', 'loss', 'drop', 'down', 'low', 'decline', 'plunge', 'tumble'];

        cryptoData.news = cryptoArticles.map(article => {
          const text = ((article.title || '') + ' ' + (article.description || '')).toLowerCase();
          const bullish = bullishWords.filter(word => text.includes(word)).length;
          const bearish = bearishWords.filter(word => text.includes(word)).length;

          return {
            title: article.title,
            published: article.publishedAt,
            sentiment: bullish > bearish ? 'bullish' : bearish > bullish ? 'bearish' : 'neutral',
            source: article.source?.name || 'NewsAPI'
          };
        });
      }
    }

    // NewsAPI Sentiment Analysis
    if (data.articles && Array.isArray(data.articles)) {
      const articles = data.articles.slice(0, 20);
      const bullishWords = ['surge', 'rally', 'bullish', 'gain', 'rise', 'up', 'high', 'boost', 'positive', 'optimistic', 'soar', 'breakthrough'];
      const bearishWords = ['crash', 'fall', 'bearish', 'loss', 'drop', 'down', 'low', 'decline', 'negative', 'pessimistic', 'plunge', 'tumble'];

      let bullishCount = 0;
      let bearishCount = 0;

      for (const article of articles) {
        const text = ((article.title || '') + ' ' + (article.description || '')).toLowerCase();

        const bullish = bullishWords.filter(word => text.includes(word)).length;
        const bearish = bearishWords.filter(word => text.includes(word)).length;

        if (bullish > bearish) {
          bullishCount++;
        } else if (bearish > bullish) {
          bearishCount++;
        }
      }

      cryptoData.social = {
        source: 'NewsAPI',
        total_articles: articles.length,
        bullish: bullishCount,
        bearish: bearishCount,
        neutral: articles.length - bullishCount - bearishCount,
        sentiment: bullishCount > bearishCount ? 'BULLISH' : bearishCount > bullishCount ? 'BEARISH' : 'NEUTRAL',
        score: ((bullishCount - bearishCount) / Math.max(articles.length, 1)).toFixed(3)
      };
    }
  }

  // Technical Indicators
  if (cryptoData.price.history && cryptoData.price.history.length > 0) {
    const prices = cryptoData.price.history;
    const sma20 = prices.slice(-20).reduce((a, b) => a + b, 0) / Math.min(20, prices.length);

    cryptoData.technical = {
      sma_20: sma20.toFixed(2),
      distance_from_sma: ((parseFloat(cryptoData.price.current) - sma20) / sma20 * 100).toFixed(2),
      trend: prices[prices.length - 1] > prices[0] ? 'BULLISH' : 'BEARISH',
      volatility: ((parseFloat(cryptoData.price.high_24h) - parseFloat(cryptoData.price.low_24h)) / parseFloat(cryptoData.price.low_24h) * 100).toFixed(2)
    };
  }

  // Overall Sentiment - Now uses news data
  const newsPositive = cryptoData.news.filter(n => n.sentiment === 'bullish').length;
  const newsNegative = cryptoData.news.filter(n => n.sentiment === 'bearish').length;

  cryptoData.overall = {
    news_bullish: newsPositive,
    news_bearish: newsNegative,
    social_sentiment: cryptoData.social.sentiment || 'NEUTRAL',
    technical_trend: cryptoData.technical.trend || 'NEUTRAL',
    combined: (newsPositive > newsNegative && cryptoData.social.sentiment === 'BULLISH') ? 'STRONG BULLISH' :
             (newsNegative > newsPositive && cryptoData.social.sentiment === 'BEARISH') ? 'STRONG BEARISH' : 'MIXED'
  };

} catch (error) {
  cryptoData.error = error.message;
  cryptoData.errorStack = error.stack;
}

return [{ json: cryptoData }];
